proof_block:
// Pre-state is unique and well-formed, so its view has no duplicates.
// Put that fact in scope -- it's the only structural lemma available on
// StaticLinkedList and helps z3 reason about pre_self_@.push(new_value).
pre_self_.unique_implys_no_duplicates();

// Prove the synthetic-ensures implication directly with `assert(P ==> Q) by`.
// The previous attempt re-asserted the post1_/post2_ ensures as free-standing
// statements, but the post-conjuncts are NOT in scope outside the implication
// -- they're only the antecedent of the ensures-implication, so a bare
// `assert(forall|v|...)` referencing post2_self_.get_node_ref(v) is
// unprovable. Wrapping everything in `assert(P ==> Q) by { if (P) { ... } }`
// brings every post-conjunct into scope inside the `if`-branch, and Verus
// only needs to discharge Q (= det_push_equal) under that hypothesis.
assert(({
    &&& (post1_self_.wf())
    &&& (post1_self_@ == pre_self_@.push(new_value))
    &&& (post1_self_.len() == pre_self_.len() + 1)
    &&& (forall|v:T|
            #![auto]
            pre_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) ==
                    post1_self_.get_node_ref(v))
    &&& (post1_self_.get_node_ref(new_value) == r1)
    &&& (post1_self_.unique())
    &&& (post2_self_.wf())
    &&& (post2_self_@ == pre_self_@.push(new_value))
    &&& (post2_self_.len() == pre_self_.len() + 1)
    &&& (forall|v:T|
            #![auto]
            pre_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) ==
                    post2_self_.get_node_ref(v))
    &&& (post2_self_.get_node_ref(new_value) == r2)
    &&& (post2_self_.unique())
}) ==> det_push_equal(r1, r2, post1_self_, post2_self_)) by {
    if post1_self_.wf()
        && (post1_self_@ == pre_self_@.push(new_value))
        && (post1_self_.len() == pre_self_.len() + 1)
        && (forall|v:T|
                #![auto]
                pre_self_@.contains(v) ==>
                    pre_self_.get_node_ref(v) ==
                        post1_self_.get_node_ref(v))
        && (post1_self_.get_node_ref(new_value) == r1)
        && post1_self_.unique()
        && post2_self_.wf()
        && (post2_self_@ == pre_self_@.push(new_value))
        && (post2_self_.len() == pre_self_.len() + 1)
        && (forall|v:T|
                #![auto]
                pre_self_@.contains(v) ==>
                    pre_self_.get_node_ref(v) ==
                        post2_self_.get_node_ref(v))
        && (post2_self_.get_node_ref(new_value) == r2)
        && post2_self_.unique()
    {
        // Both post-views are pinned to the same sequence pre_self_@.push(new_value).
        // Surface seq extensionality so z3 has a single shared spec_seq.
        assert(post1_self_@ == pre_self_@.push(new_value));
        assert(post2_self_@ == pre_self_@.push(new_value));
        assert(post1_self_@ =~= post2_self_@);

        // Lengths are pinned in both runs.
        assert(post1_self_.len() == pre_self_.len() + 1);
        assert(post2_self_.len() == pre_self_.len() + 1);
        assert(post1_self_.len() == post2_self_.len());

        // Pointwise agreement of get_node_ref on every value already in pre_self_:
        // the two `forall|v|` ensures-conjuncts share the trigger
        // `pre_self_.get_node_ref(v)`, so chaining gives equality of the
        // post1_/post2_ side.
        assert forall|v: T| pre_self_@.contains(v) implies
            post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
            // discharged via transitivity through pre_self_.get_node_ref(v).
        };

        // r1 / r2 are pinned to post1_/post2_.get_node_ref(new_value).
        assert(r1 == post1_self_.get_node_ref(new_value));
        assert(r2 == post2_self_.get_node_ref(new_value));
    }
};
